class Conversation:
    """对话会话"""
    def __init__(
        self,
        conversation_id: Optional[str] = None,
        title: str = "新对话",
        system_prompt: Optional[str] = None
    ):
        self.conversation_id = conversation_id or str(uuid.uuid4())
        self.title = title
        self.system_prompt = system_prompt or "You are a professional AI programmer who will carefully think, thoroughly analyze, and diligently fulfill all user requirements."
        self.messages: List[Message] = []
        self.created_at = datetime.now().isoformat()
        self.updated_at = self.created_at
        self.metadata: Dict[str, Any] = {}

    def add_message(self, role: str, content: str, metadata: Optional[Dict] = None):
        """添加消息"""
        message = Message(role=role, content=content, metadata=metadata)
        self.messages.append(message)
        self.updated_at = datetime.now().isoformat()

        # 自动更新标题（使用第一条用户消息）
        if role == "user" and self.title == "新对话" and len(self.messages) <= 2:
            self.title = content[:50] + ("..." if len(content) > 50 else "")

    def get_messages(self, include_system: bool = True) -> List[Dict]:
        """获取消息列表"""
        messages = []

        if include_system and self.system_prompt:
            messages.append({
                "role": "system",
                "content": self.system_prompt
            })

        for msg in self.messages:
            messages.append({
                "role": msg.role,
                "content": msg.content
            })

        return messages

    def get_context_window(self, max_messages: int = 10) -> List[Dict]:
        """获取最近的N条消息作为上下文"""
        messages = []

        if self.system_prompt:
            messages.append({
                "role": "system",
                "content": self.system_prompt
            })

        # 获取最近的消息
        recent_messages = self.messages[-max_messages:] if len(self.messages) > max_messages else self.messages

        for msg in recent_messages:
            messages.append({
                "role": msg.role,
                "content": msg.content
            })

        return messages

    def clear_messages(self):
        """清空消息历史"""
        self.messages = []
        self.updated_at = datetime.now().isoformat()

    def to_dict(self) -> Dict:
        """转换为字典"""
        return {
            "conversation_id": self.conversation_id,
            "title": self.title,
